THE RISK:
{
 "id": "avl-foreclosure-of-the-large-operator-channel",
 "title": "Approved-vendor-list machinery forecloses the large-operator 40% for the entire Year-1 window",
 "narrative": "The venture's stated first channel is large operators — the biggest cell in the buyer mix at 0.40. But large operators procure rack power through approved-vendor lists, multi-year framework agreements, and reference-install requirements, and every leader list in the corpus names the same 5–7 entrenched suppliers already inside those frameworks. The reference class of industrial entrants into EU DC hardware got in via OEM white-label and distribution, not direct-to-operator. The 0.40 cell itself rests on a single misused datapoint (one supplier's order mix, not a market channel split). The risk is not that this slice is slow — it is that it is structurally closed to a pre-launch entrant for the duration of the YAM window, which means the model's largest customer cell should be removed from reachable scope, not ramped slowly.",
 "category": "execution",
 "targetNodes": [
  "cust.operator-large"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The GTM plan targets large operators first, but these buyers run AVL/framework procurement with reference-install prerequisites, and the incumbent set that populates those AVLs is the same 5–7 vendors across every published leader list",
   "refs": [
    "profile:Primary buyer",
    "digest:cr3-vendors#c6",
    "digest:cr3-vendors#c7"
   ]
  },
  {
   "step": "propagation",
   "text": "A pre-launch entrant with zero installed base cannot satisfy prequalification, so it cannot even enter the tenders that constitute this demand; the 0.40 weight has no evidential basis as entrant-reachable demand — its only evidence is one supplier's company-level order statistic",
   "refs": [
    "ledger:cust.operator-large",
    "digest:cr3-vendors#c5",
    "digest:obtainable-benchmark#c9"
   ]
  },
  {
   "step": "model-impact",
   "text": "The largest customerType cell is unavailable to the venture within the obtainable horizon: SAM as experienced by this entrant excludes the operator-large slice, and Year-1 pipeline built against it converts to zero",
   "refs": [
    "ledger:cust.operator-large",
    "ledger:obtainableFactor"
   ]
  }
 ],
 "whyMissable": "The buyer-mix table makes large operators look like the biggest, most efficient door — 'sell where the money is' is the natural read, and the profile encodes it. What the surface hides is that the slice is defined by procurement machinery (AVLs, frameworks, reference requirements) that no ledger node represents; the mix node quantifies who spends, not who is open to a new supplier.",
 "expectedObviousness": "low",
 "falsifier": "A top-tier CE operator (hyperscaler or top-5 colocation provider) issuing a rack-PDU RFQ open to suppliers without a prior reference installation, or written confirmation that its AVL admits new vendors on a sub-12-month qualification track.",
 "likelihood": {
  "value": 0.5,
  "rationale": "Base rate for the reference class: industrial hardware entrants into EU data-center supply chains overwhelmingly enter via OEM/distribution first; direct operator AVL entry inside 12 months from a standing start is rare, though a differentiated product with an executive sponsor occasionally breaks through [evidence revision: Evidence directly supports the AVL/framework/spec machinery and entrenched-incumbent premises, and the OEM/white-label reference class. However, the sources establish that qualification barriers exist but do not quantify that a new vendor is fully foreclosed for the entire Year-1 window (the strongest form of the claim), and no direct falsifier appeared. Modest upward revision from 0.45 to 0.50 reflects corroboration of the mechanism while respecting that 'entire window' foreclosure remains partly inferential.]",
  "basis": "evidence",
  "revisedFrom": 0.45
 },
 "perturbation": [
  {
   "nodeId": "cust.operator-large",
   "op": "exclude",
   "note": "Foreclosure, not shrinkage: the operator-large cell is unavailable to a pre-launch entrant within the Year-1 window"
  }
 ],
 "indicators": [
  {
   "signal": "Prequalification clauses in CE colocation and hyperscale fit-out tenders (reference installs, minimum trading history, framework membership)",
   "where": "Supplier portals of major CE operators (e.g., Equinix, NTT, Vantage EMEA procurement portals) and Frankfurt/Amsterdam fit-out RFQs",
   "threshold": "≥2 of the first 5 relevant RFQs require reference installs or ≥3-year supply track record",
   "updates": "increases"
  },
  {
   "signal": "Where inbound and early pipeline demand actually routes",
   "where": "The venture's own CRM: channel of the first 10 qualified conversations",
   "threshold": ">70% of engaged demand arrives via integrator/OEM/distributor rather than operator direct",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Run the three structured CE operator/distributor interviews already named in the node's promotion path, scripted specifically on AVL entry requirements and qualification timelines",
   "type": "information",
   "voiNodeId": "cust.operator-large",
   "note": "Directly tests whether the 0.40 cell is reachable in-window or foreclosed"
  },
  {
   "action": "Re-sequence GTM: Year 1 through OEM/integrator white-label and distribution (where onboarding is an annual cycle but open), with operator AVL entry staged as a Year-2 objective backed by reference installs from the indirect channel",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Converts the foreclosed cell into a Year-2+ target instead of a Year-1 dependency"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "Project Olympus Universal Power Distribution Unit Specification",
   "sourceType": "industry-report",
   "publisher": "Open Compute Project / Microsoft",
   "date": "2017-11-01",
   "excerpt": "Project Olympus Universal Power Distribution Unit Specification, Author: Shaun Harris, Architect, Microsoft — evidence that hyperscalers define proprietary PDU specifications that vendors must meet.",
   "url": "https://www.opencompute.org/documents/microsoft-project-olympus-universal-pdu-specification",
   "attached": true
  },
  {
   "title": "HE Framework for Supply, Installation and management of Data Centre Management equipment and Infrastructure (2024)",
   "sourceType": "industry-report",
   "publisher": "NEUPC Ltd / Find a Tender",
   "date": "2024-03-18",
   "excerpt": "Multi-buyer framework contract award for supply and installation of data centre equipment — confirms framework-based procurement structure with formal qualification.",
   "url": "https://www.find-tender.service.gov.uk/Notice/008632-2024",
   "attached": true
  },
  {
   "title": "White-Label Modular Data Centers for System Integrators",
   "sourceType": "industry-report",
   "publisher": "Moduledge",
   "date": "2026-02-15",
   "excerpt": "White-label modular data centers let integrators deliver turnkey infrastructure under their own brand — corroborates the reference-class entry path via OEM/white-label rather than direct-to-operator.",
   "url": "https://www.moduledge.com/blog/system-integrator-white-label-modular-data-center-guide",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.opencompute.org/index.php/sp/agreements",
   "stance": "supports",
   "quote": "These guidelines and agreements apply to approved OCP Colo Solution Providers seeking OCP Ready™ certification for a colocation data center facility."
  },
  {
   "url": "https://www.opencompute.org/documents/microsoft-project-olympus-universal-pdu-specification",
   "stance": "supports",
   "quote": "Project Olympus \nUniversal Power Distribution \nUnit\nSpecification\nAuthor:\nShaun Harris, Architect, Microsoft"
  },
  {
   "url": "https://www.find-tender.service.gov.uk/Notice/008632-2024",
   "stance": "supports",
   "quote": "HE Framework for Supply, Installation and management of Data Centre Management equipment and Infrastructure (2024)"
  },
  {
   "url": "https://www.vertiv.com/49858a/globalassets/documents/brochures/vertiv-partner-program-emea-2024-en.pdf",
   "stance": "supports",
   "quote": "MAJOR CUSTOMERS Alibaba, Alstom, America Movil, AT&T, China Mobile, Equinix, Ericsson, Reliance, Siemens, Telefonica, Tencent, Verizon and Vodafone"
  },
  {
   "url": "https://www.moduledge.com/blog/system-integrator-white-label-modular-data-center-guide",
   "stance": "supports",
   "quote": "White-label modular data centers let integrators deliver turnkey edge infrastructure under their own brand, with 3–6 month timelines and margins that actually make sense."
  },
  {
   "url": "https://www.facilitiesdive.com/news/schneider-electric-announces-major-data-center-order-white-space-collabo/759714/",
   "stance": "silent",
   "quote": "The collaboration with Compass Datacenters is intended to accelerate data center delivery timelines by offering a module with a high-power busway, network cabling and a water-based cooling loop."
  }
 ]
}

